// --- Proyección geográfica real (equirectangular simple) ---
const LAT_MIN = -39.6, LAT_MAX = -33.0, LON_MIN = -63.6, LON_MAX = -56.3;
const VBW = 760, VBH = 860;
function project(lat, lon) {
  const x = ((lon - LON_MIN) / (LON_MAX - LON_MIN)) * VBW;
  const y = ((LAT_MAX - lat) / (LAT_MAX - LAT_MIN)) * VBH;
  return [x, y];
}
function segmentsToPath(segments) {
  return segments.map((seg) => {
    const p = seg.map(([lon, lat]) => project(lat, lon));
    return "M" + p.map(([x, y]) => `${x.toFixed(1)},${y.toFixed(1)}`).join("L");
  }).join(" ");
}
function polysToPath(polys) {
  return polys.map((poly) =>
    poly.map((ring) => {
      const p = ring.map(([lon, lat]) => project(lat, lon));
      return "M" + p.map(([x, y]) => `${x.toFixed(1)},${y.toFixed(1)}`).join("L") + "Z";
    }).join(" ")
  ).join(" ");
}
function pointsToDots(points) {
  return points.map(([lon, lat]) => project(lat, lon));
}

